use std::collections::HashMap;use std::io::{self,Read};fn pal(s:&str)->bool{s.as_bytes().iter().eq(s.as_bytes().iter().rev())}fn rev(s:&str)->String{s.chars().rev().collect()}fn solve(w:&[String])->Vec<(usize,usize)>{let mut pos=HashMap::new();for(i,s)in w.iter().enumerate(){pos.insert(s.clone(),i);}let mut ans=Vec::new();for(i,s)in w.iter().enumerate(){for c in 0..=s.len(){let pre=&s[..c];let suf=&s[c..];if pal(pre){if let Some(&j)=pos.get(&rev(suf)){if j!=i{ans.push((j,i));}}}if c<s.len()&&pal(suf){if let Some(&j)=pos.get(&rev(pre)){if j!=i{ans.push((i,j));}}}}}ans.sort();ans}fn fmt(p:&[(usize,usize)])->String{format!("[{}]",p.iter().map(|(a,b)|format!("[{},{}]",a,b)).collect::<Vec<_>>().join(","))}fn main(){let mut s=String::new();io::stdin().read_to_string(&mut s).unwrap();let d:Vec<String>=s.split_whitespace().map(|x|x.to_string()).collect();if d.is_empty(){return};let mut idx=0;let t:usize=d[idx].parse().unwrap();idx+=1;let mut out=Vec::new();for _ in 0..t{let n:usize=d[idx].parse().unwrap();idx+=1;let mut w=Vec::new();for _ in 0..n{let x=if d[idx]=="_"{"".to_string()}else{d[idx].clone()};idx+=1;w.push(x);}out.push(fmt(&solve(&w)));}print!("{}",out.join("\n\n"));}
